module RefModule(input [32-1:0] din, 
                                   input clk, en, rst,
                                   output reg [32-1:0] dout
    );always @(posedge clk)
  wire [31:0] _tap_din = din & {32{1'b1}};

begin
  if(rst)
  dout <= 0;

  else
  if(en)
    dout <= din;

end 


endmodule
